select *
FROM jsh_supplier
where 1=1


    and supplier like #{bindSupplier}


    and type=#{type}



    and contacts like #{bindContacts}



    and phone_num like #{bindPhoneNum}



    and telephone like #{bindTelephone}


    and creator in (

        #{creator}

    )

and ifnull(delete_flag,'0') !='1'
order by sort asc, id desc

select *
FROM jsh_supplier
where 1=1


    and supplier like #{bindSupplier}


    and type=#{type}



    and phone_num like #{bindPhoneNum}



    and telephone like #{bindTelephone}

and ifnull(delete_flag,'0') !='1'
order by sort asc, id desc

mapper.update:
update jsh_supplier
set delete_flag='1'
where 1=1
and id in (

    #{id}

)

mapper.select:
select id, supplier from jsh_supplier
where id = #{id}
and ifnull(delete_flag,'0') !='1'

SELECT s.id as customer_id, s.supplier as customer_name, s.telephone as phone, s.customer_level, s.customer_source, COUNT(DISTINCT dh.id) as order_count, IFNULL(SUM(dh.total_price), 0) as total_amount, IFNULL(AVG(dh.total_price), 0) as avg_amount, MAX(dh.bill_time) as last_order_time, DATEDIFF(NOW(), MAX(dh.bill_time)) as days_since_last_order, CASE WHEN COUNT(DISTINCT dh.id) >= 10 AND IFNULL(SUM(dh.total_price), 0) >= 5000 THEN '高价值客户' WHEN COUNT(DISTINCT dh.id) >= 5 AND IFNULL(SUM(dh.total_price), 0) >= 2000 THEN '重要客户' WHEN COUNT(DISTINCT dh.id) >= 1 THEN '普通客户' ELSE '潜在客户' END as value_level, COUNT(DISTINCT cfu.id) as follow_up_count, MAX(cfu.follow_up_time) as last_follow_up_time, CASE WHEN COUNT(DISTINCT cfu.id) = 0 THEN '未跟进' WHEN DATEDIFF(NOW(), MAX(cfu.follow_up_time)) > 30 THEN '需跟进' ELSE '跟进正常' END as follow_up_status FROM jsh_supplier s LEFT JOIN jsh_depot_head dh ON s.id = dh.organ_id AND dh.type IN ('销售出库', '零售出库') AND dh.delete_flag = '0'
AND dh.bill_time >= #{beginTime}
AND dh.bill_time <= #{endTime}
LEFT JOIN jsh_customer_follow_up cfu ON s.id = cfu.customer_id AND cfu.delete_flag = '0' WHERE s.type IN ('客户', '会员') AND s.delete_flag = '0'
AND s.supplier LIKE CONCAT('%', #{customerName}, '%')
AND s.customer_level = #{customerLevel}
AND s.customer_source = #{customerSource}
AND s.creator IN (
#{creator}
)
GROUP BY s.id, s.supplier, s.telephone, s.customer_level, s.customer_source HAVING 1=1
AND CASE WHEN COUNT(DISTINCT dh.id) >= 10 AND IFNULL(SUM(dh.total_price), 0) >= 5000 THEN '高价值客户' WHEN COUNT(DISTINCT dh.id) >= 5 AND IFNULL(SUM(dh.total_price), 0) >= 2000 THEN '重要客户' WHEN COUNT(DISTINCT dh.id) >= 1 THEN '普通客户' ELSE '潜在客户' END = #{valueLevel}
ORDER BY total_amount DESC, order_count DESC

SELECT COUNT(1) FROM (
    SELECT s.id
    FROM jsh_supplier s
    LEFT JOIN jsh_depot_head dh ON s.id = dh.organ_id
        AND dh.type IN ('销售出库', '零售出库')
        AND dh.delete_flag = '0'

            AND dh.bill_time >= #{beginTime}


            AND dh.bill_time <= #{endTime}

    WHERE s.type IN ('客户', '会员')
    AND s.delete_flag = '0'

        AND s.supplier LIKE CONCAT('%', #{customerName}, '%')


        AND s.customer_level = #{customerLevel}


        AND s.customer_source = #{customerSource}


        AND s.creator IN (

            #{creator}

        )

    GROUP BY s.id
    HAVING 1=1

        AND CASE
            WHEN COUNT(DISTINCT dh.id) >= 10 AND IFNULL(SUM(dh.total_price), 0) >= 5000 THEN '高价值客户'
            WHEN COUNT(DISTINCT dh.id) >= 5 AND IFNULL(SUM(dh.total_price), 0) >= 2000 THEN '重要客户'
            WHEN COUNT(DISTINCT dh.id) >= 1 THEN '普通客户'
            ELSE '潜在客户'
        END = #{valueLevel}

) t
